                  <span className="text-slate-400 flex items-center">
                    <Clock size={14} className="mr-2" /> Previsão
                  </span>
                  <span className="text-slate-700 font-semibold">{new Date(service.endDate).toLocaleDateString('pt-BR')}</span>
