  const handleAddRepresentative = async (data: Omit<Representative, 'id'>) => {
    try {
      await addDoc(collection(db, 'cliente', client.id, 'representantes'), {
        ...data,
        createdAt: serverTimestamp()
      });
    } catch (err) {
      console.error("Erro ao adicionar representante:", err);
