        <div className="border border-slate-200">
           <div className="bg-[#BDB76B]/30 py-1 px-4 text-center font-black uppercase border-b border-slate-200">DESCRIÇÃO DOS SERVIÇOS</div>
           <div className="p-4 bg-white text-justify min-h-[100px] leading-relaxed">{servicosDesc}</div>
           <div className="bg-[#BDB76B]/30 py-1 px-4 text-center font-black uppercase border-y border-slate-200">Responsabilidade JPS Steel</div>
           <div className="p-4 bg-white italic text-slate-700">{porContaJps}</div>
           <div className="bg-[#BDB76B]/30 py-1 px-4 text-center font-black uppercase border-y border-slate-200">Responsabilidade Contratante</div>
           <div className="p-4 bg-white italic text-slate-700">{porContaContratante}</div>
        </div>

        <div className="flex justify-end">
          <div className="bg-[#BDB76B] text-white py-3 px-10 font-black text-xl shadow-md">
            Valor Global: R$ {valorGlobal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </div>
        </div>

        <div className="pt-12">
          <p className="font-black italic">Atenciosamente,</p>
          <div className="mt-4">
            <p className="font-black text-slate-800 leading-none">Patricia Santos</p>
            <p className="text-xs text-slate-500 italic mt-1">Gestão & Negócios | (14) 99737-1221</p>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <style>{`
        @media print {
          body * { visibility: hidden; }
          #printable-budget, #printable-budget * { visibility: visible; }
          #printable-budget { position: absolute; left: 0; top: 0; width: 100%; }
        }
