        </div>

        <div className="mt-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div>
            <p className="text-blue-400 font-black text-[10px] uppercase tracking-widest mb-1">Valor Global Final</p>
            <p className="text-5xl font-black text-white">R$ {valorGlobal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
          </div>
          <button 
            type="button" 
            onClick={onFinish} 
            className="bg-blue-600 hover:bg-blue-500 text-white px-10 py-5 rounded-[2rem] font-black shadow-xl shadow-blue-900/40 flex items-center space-x-3 transition-all active:scale-95"
          >
            <span>GERAR DOCUMENTO</span>
            <Eye size={20} />
