function doPost(e) {
  const sheetId = "1qNY05Px9sYomFJhCvEJ5XXWUxS1L7l_w0g7D-jPf5W0";
  const sheetName = "orcamento";

  try {
    const sheet = SpreadsheetApp
      .openById(sheetId)
      .getSheetByName(sheetName);

    const payload = JSON.parse(e.postData.contents);

    // Converte YYYY-MM-DD para DD/MM/YYYY
    function formatDateBR(dateStr) {
      if (!dateStr) return "";
      const parts = dateStr.split("-");
      return `${parts[2]}/${parts[1]}/${parts[0]}`;
    }

    // Data e hora atual
    const now = new Date();
    const tz = Session.getScriptTimeZone();
    const dataHora = Utilities.formatDate(
      now,
      tz,
      "dd/MM/yy 'às' HH:mm"
    );

    const novaLinha = [
      payload.idOrc || "",                                  // A
      formatDateBR(payload.dataProposta),                  // B
      payload.clienteOrc || "",                             // C
      payload.responsavelOrc || "",                         // D
      payload.departamentoOrc || "",                        // E
      payload.referenciaOrc || "",                          // F
      payload.descricaoOrc || "",                           // G
      (payload.contaJPS || []).join(", "),                  // H
      (payload.contaContratante || []).join(", "),          // I
      payload.valorGlobal || 0,                             // J
      formatDateBR(payload.prazo),                          // K
      `Orçamento recebido em: ${dataHora}`,                 // L
      ""                                                    // M
    ];

    const linhaDestino = sheet.getLastRow() + 1;
    sheet.getRange(linhaDestino, 1, 1, novaLinha.length)
         .setValues([novaLinha]);

    // Formatação moeda BRL
    sheet.getRange(linhaDestino, 10)
         .setNumberFormat("R$ #,##0.00");

    // 🔁 RETORNO DE SUCESSO
    return ContentService
      .createTextOutput(
        JSON.stringify({
          sucesso: true,
          mensagem: "Dados recebidos e gravados com sucesso na planilha."
        })
      )
      .setMimeType(ContentService.MimeType.JSON);

  } catch (erro) {

    // 🔁 RETORNO DE ERRO (caso aconteça)
    return ContentService
      .createTextOutput(
        JSON.stringify({
          sucesso: false,
          mensagem: "Erro ao gravar dados.",
          detalhe: erro.message
        })
      )
      .setMimeType(ContentService.MimeType.JSON);
  }
}

