        <form onSubmit={handleSubmit} className="p-8 space-y-5">
          {/* Toggle Tipo */}
          <div className="flex p-1.5 bg-slate-100 rounded-2xl border border-slate-200/50">
            <button 
              type="button"
              onClick={() => setFormData({...formData, tipo: 'Entrada'})}
              className={`flex-1 py-3 text-xs font-black rounded-xl transition-all flex items-center justify-center ${formData.tipo === 'Entrada' ? 'bg-white text-green-600 shadow-lg scale-100' : 'text-slate-500 scale-95 opacity-60'}`}
            >
              <ArrowUpRight size={16} className="mr-2" /> ENTRADA
            </button>
            <button 
              type="button"
              onClick={() => setFormData({...formData, tipo: 'Saída'})}
              className={`flex-1 py-3 text-xs font-black rounded-xl transition-all flex items-center justify-center ${formData.tipo === 'Saída' ? 'bg-white text-red-600 shadow-lg scale-100' : 'text-slate-500 scale-95 opacity-60'}`}
            >
              <ArrowDownRight size={16} className="mr-2" /> SAÍDA
            </button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Categoria</label>
              <input 
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-blue-500/5 transition-all text-sm font-bold outline-none"
                placeholder="Ex: Insumos, Obra..."
                value={formData.categoria}
