export const InventoryMovements: React.FC = () => {
  const [movements, setMovements] = useState<Movement[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isSuccessModalOpen, setIsSuccessModalOpen] = useState(false);
  const [lastType, setLastType] = useState<'Entrada' | 'Saída'>('Entrada');
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    // Escutar Financeiro
    const q = query(collection(db, 'financeiro'));
    const unsubMovements = onSnapshot(q, (snap) => {
      const data = snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Movement));
      // Ordenação JS para evitar erro de índice ausente no Firebase
      data.sort((a, b) => {
        const dateA = new Date(a.vencimento).getTime();
        const dateB = new Date(b.vencimento).getTime();
        return dateB - dateA;
      });
      setMovements(data);
    });

    // Escutar Clientes para exibição de nomes na tabela
    const unsubClients = onSnapshot(collection(db, 'cliente'), (snap) => {
      setClients(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Client)));
    });

    return () => {
      unsubMovements();
      unsubClients();
    };
  }, []);

  const handleSuccess = (tipo: 'Entrada' | 'Saída') => {
    setLastType(tipo);
    setIsSuccessModalOpen(true);
  };

  const totalIn = movements.filter(m => m.tipo === 'Entrada' && m.status !== 'Cancelado').reduce((acc, curr) => acc + curr.valor, 0);
  const totalOut = movements.filter(m => m.tipo === 'Saída' && m.status !== 'Cancelado').reduce((acc, curr) => acc + curr.valor, 0);
  const balance = totalIn - totalOut;

  const filteredMovements = movements.filter(m => 
    m.descricao.toLowerCase().includes(searchTerm.toLowerCase()) ||
    m.categoria.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const SuccessModal = () => (
    <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[100] flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-sm rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
        <div className="p-10 flex flex-col items-center text-center">
          <div className="w-48 h-48 mb-8 rounded-[2rem] overflow-hidden shadow-2xl ring-8 ring-slate-100/50">
            <img 
              src={lastType === 'Entrada' ? "https://i.ibb.co/BHDrNhKG/avatar-Rico.png" : "https://i.ibb.co/DD45WXrG/avatar-Pobre.png"} 
              alt="Resultado Financeiro" 
              className="w-full h-full object-cover"
            />
          </div>

          <h3 className="text-2xl font-black text-slate-900 mb-2">Movimentação Salva!</h3>
          <p className="text-slate-500 text-sm font-medium leading-relaxed mb-10">
            O lançamento de <span className={`font-bold ${lastType === 'Entrada' ? 'text-green-600' : 'text-red-600'}`}>{lastType.toLowerCase()}</span> foi registrado com sucesso no banco de dados da JPS Steel.
          </p>

          <button
            onClick={() => setIsSuccessModalOpen(false)}
            className="w-full py-4 bg-slate-900 hover:bg-slate-800 text-white font-black rounded-2xl shadow-xl transition-all active:scale-95"
          >
            VOLTAR AO FINANCEIRO
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-800">Fluxo Financeiro</h1>
          <p className="text-slate-500 text-sm">Controle rigoroso de entradas, saídas e previsões.</p>
        </div>
        <button 
          onClick={() => setIsFormOpen(true)}
          className="flex items-center justify-center space-x-2 bg-slate-900 hover:bg-slate-800 text-white px-8 py-3.5 rounded-2xl font-black shadow-xl shadow-slate-900/20 transition-all active:scale-95"
        >
          <Plus size={20} strokeWidth={3} />
          <span>NOVA MOVIMENTAÇÃO</span>
        </button>
