import { db } from '../firebase';
import { Movement, Client } from '../types';
import { ConfirmationDialog } from './ConfirmationDialog';

interface MovementListWidgetProps {
  movements: Movement[];
  clients: Client[];
  onEdit: (movement: Movement) => void;
}

