  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    tipo: 'Entrada' as 'Entrada' | 'Saída',
    categoria: '',
    descricao: '',
    valor: '',
    status: 'Pendente' as Movement['status'],
    vencimento: new Date().toISOString().split('T')[0],
