                        <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Tudo em dia!</p>
                      </div>
                    ) : (
                      <div className="divide-y divide-slate-100">
                        {pendingMovements.map((mov) => (
                          <button 
                            key={mov.id}
