import React, { useState } from 'react';
import { Sparkles, Loader2, Send, BrainCircuit, X, TrendingUp, TrendingDown, Wallet, AlertCircle } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { collection, query, where, getDocs, updateDoc, doc, addDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '../firebase';
import { Client, Movement } from '../types';

interface AICommandCenterProps {
  clients: Client[];
  movements: Movement[];
}

export const AICommandCenter: React.FC<AICommandCenterProps> = ({ clients, movements }) => {
  const [input, setInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [summaryData, setSummaryData] = useState<{ text: string; analysis: any } | null>(null);

  const handleCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isProcessing) return;

    setIsProcessing(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Definição das funções que a IA pode chamar
    const tools = [{
      functionDeclarations: [
        {
          name: 'processPayment',
          description: 'Registra ou consolida um pagamento realizado para um cliente ou fornecedor.',
          parameters: {
            type: Type.OBJECT,
            properties: {
              clientName: { type: Type.STRING, description: 'Nome do cliente ou fornecedor mencionado.' },
              amount: { type: Type.NUMBER, description: 'Valor monetário da transação.' },
              description: { type: Type.STRING, description: 'Breve descrição da transação.' }
            },
            required: ['clientName', 'amount']
          }
        },
        {
          name: 'getFinancialHealth',
          description: 'Gera uma análise completa das finanças, economias e saldo do mês atual.',
          parameters: {
            type: Type.OBJECT,
            properties: {
              focus: { type: Type.STRING, description: 'Foco da análise (ex: economias, gastos, previsões).' }
            }
          }
        }
      ]
    }];

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: input,
        config: { 
          tools,
          systemInstruction: 'Você é o assistente inteligente da JPS Steel - Montagens Industriais. Sua função é ajudar o gestor a operar o financeiro e entender a saúde da empresa através de comandos de voz ou texto. Seja direto, profissional e focado em resultados industriais.'
        },
      });

      const call = response.functionCalls?.[0];

      if (call?.name === 'processPayment') {
        const { clientName, amount } = call.args as any;
        await handlePaymentLogic(clientName, amount);
        setInput('');
        alert(`IA JPS: Processamento de R$ ${amount} para "${clientName}" concluído.`);
      } else if (call?.name === 'getFinancialHealth') {
        await handleSummaryLogic();
      } else {
        alert("IA JPS: " + (response.text || "Comando recebido. Como posso ajudar mais?"));
      }

    } catch (error) {
      console.error("Erro na IA:", error);
      alert("Houve um erro ao processar seu comando via IA.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePaymentLogic = async (clientName: string, amount: number) => {
    // 1. Tenta achar o cliente
    const client = clients.find(c => 
      c.displayName.toLowerCase().includes(clientName.toLowerCase())
    );

    if (client) {
      // 2. Busca movimentação pendente com esse valor e cliente
      const q = query(
        collection(db, 'financeiro'),
        where('idRelacionado', '==', client.id),
        where('valor', '==', amount),
        where('status', '==', 'Pendente')
      );

      const snap = await getDocs(q);

      if (!snap.empty) {
        // Consolidar existente
        await updateDoc(doc(db, 'financeiro', snap.docs[0].id), {
          status: 'Consolidado',
          updatedAt: serverTimestamp(),
          observacao: 'Consolidado via JPS AI Assistant'
        });
      } else {
        // Criar nova consolidada
        await addDoc(collection(db, 'financeiro'), {
          tipo: 'Saída',
          categoria: 'Geral',
          descricao: `Pagamento para ${client.displayName} (via IA)`,
          valor: amount,
          status: 'Consolidado',
          vencimento: new Date().toISOString().split('T')[0],
          idRelacionado: client.id,
          createdAt: serverTimestamp()
        });
      }
    } else {
      // Criar sem vínculo de cliente
      await addDoc(collection(db, 'financeiro'), {
        tipo: 'Saída',
        categoria: 'Geral',
        descricao: `Pagamento para ${clientName} (via IA)`,
        valor: amount,
        status: 'Consolidado',
        vencimento: new Date().toISOString().split('T')[0],
        idRelacionado: '',
        createdAt: serverTimestamp()
      });
    }
  };

  const handleSummaryLogic = async () => {
    const totalIn = movements.filter(m => m.tipo === 'Entrada' && m.status !== 'Cancelado').reduce((acc, curr) => acc + curr.valor, 0);
    const totalOut = movements.filter(m => m.tipo === 'Saída' && m.status !== 'Cancelado').reduce((acc, curr) => acc + curr.valor, 0);
    const pending = movements.filter(m => m.status === 'Pendente').reduce((acc, curr) => acc + curr.valor, 0);

    const prompt = `Analise os seguintes dados financeiros da JPS Steel:
    Total de Entradas: R$ ${totalIn}
    Total de Saídas: R$ ${totalOut}
    Saldo Atual: R$ ${totalIn - totalOut}
    Total Pendente: R$ ${pending}

    Gere um resumo executivo curto, motivador e estratégico para o dono da empresa sobre como estão as economias este mês.`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
