                  </div>
                  <div>
                    <h3 className="font-black text-xl uppercase tracking-tighter">Saúde Financeira IA</h3>
                    <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">Relatório Analítico JPS Steel</p>
                  </div>
