import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area 
} from 'recharts';
import { 
  Users, 
  Briefcase, 
  TrendingUp, 
  AlertCircle,
  ArrowUpRight,
  ArrowDownRight,
  Clock,
  Calendar
} from 'lucide-react';
import { collection, onSnapshot, query, orderBy, limit } from 'firebase/firestore';
import { db } from '../firebase';
import { Client, Service, Movement } from '../types';
import { AICommandCenter } from './AICommandCenter';

export const Dashboard: React.FC = () => {
  const [clients, setClients] = useState<Client[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [movements, setMovements] = useState<Movement[]>([]);

  useEffect(() => {
    const unsubClients = onSnapshot(collection(db, 'cliente'), (snap) => {
      setClients(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Client)));
    });

    const unsubServices = onSnapshot(collection(db, 'services'), (snap) => {
      setServices(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Service)));
    });

    const unsubMovements = onSnapshot(collection(db, 'financeiro'), (snap) => {
      setMovements(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Movement)));
    });

    return () => {
      unsubClients();
      unsubServices();
      unsubMovements();
    };
  }, []);

  // 1. Estatísticas Calculadas
  const stats = useMemo(() => {
    const today = new Date();
    const currentMonth = today.getMonth();
    const currentYear = today.getFullYear();

    // Total Clientes
    const totalClients = clients.length;

    // Serviços Ativos (Pendente ou Em Andamento)
    const activeServices = services.filter(s => s.status === 'Em Andamento' || s.status === 'Pendente').length;

    // Faturamento Mês (Soma das Entradas no mês atual que não estão canceladas/arquivadas)
    const monthlyRevenue = movements
      .filter(m => {
        if (m.tipo !== 'Entrada' || m.status === 'Cancelado' || m.status === 'Arquivado') return false;
        const vDate = new Date(m.vencimento + 'T12:00:00');
        return vDate.getMonth() === currentMonth && vDate.getFullYear() === currentYear;
      })
      .reduce((acc, curr) => acc + curr.valor, 0);

    // Valor Total das Movimentações Pendentes (Independente do mês)
    const pendingTotal = movements
      .filter(m => m.status === 'Pendente')
      .reduce((acc, curr) => acc + curr.valor, 0);

    return [
      { label: 'Total Clientes', value: totalClients, icon: Users, color: 'text-blue-600', bg: 'bg-blue-50' },
      { label: 'Serviços Ativos', value: activeServices, icon: Briefcase, color: 'text-orange-600', bg: 'bg-orange-50' },
      { label: 'Faturamento Mês', value: `R$ ${monthlyRevenue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`, icon: TrendingUp, color: 'text-green-600', bg: 'bg-green-50' },
      { label: 'Total Pendente', value: `R$ ${pendingTotal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`, icon: AlertCircle, color: 'text-red-600', bg: 'bg-red-50' },
    ];
  }, [clients, services, movements]);

  // 2. Dados do Gráfico (Últimos 6 meses)
  const chartData = useMemo(() => {
    const monthNames = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];

    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const m = d.getMonth();
      const y = d.getFullYear();

      const revenue = movements
        .filter(mov => {
          if (mov.tipo !== 'Entrada' || mov.status === 'Cancelado' || mov.status === 'Arquivado') return false;
          const vDate = new Date(mov.vencimento + 'T12:00:00');
          return vDate.getMonth() === m && vDate.getFullYear() === y;
        })
        .reduce((acc, curr) => acc + curr.valor, 0);

      const costs = movements
        .filter(mov => {
          if (mov.tipo !== 'Saída' || mov.status === 'Cancelado' || mov.status === 'Arquivado') return false;
          const vDate = new Date(mov.vencimento + 'T12:00:00');
          return vDate.getMonth() === m && vDate.getFullYear() === y;
        })
        .reduce((acc, curr) => acc + curr.valor, 0);

      last6Months.push({
        name: monthNames[m],
        revenue,
        costs
      });
    }
    return last6Months;
  }, [movements]);

  // 3. Próximas Movimentações (5 próximas a partir de hoje)
  const upcomingMovements = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    return movements
      .filter(m => m.vencimento >= todayStr && m.status !== 'Arquivado' && m.status !== 'Cancelado')
      .sort((a, b) => a.vencimento.localeCompare(b.vencimento))
      .slice(0, 5);
  }, [movements]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">Painel Analítico</h1>
          <p className="text-slate-500 text-sm font-medium">Acompanhamento consolidado da JPS Steel.</p>
        </div>
      </div>

      {/* AI CommandCenter INTEGRATION */}
      <AICommandCenter clients={clients} movements={movements} />

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm hover:shadow-md transition-all group">
            <div className="flex items-center justify-between mb-4">
              <div className={`p-3 rounded-2xl ${stat.bg} ${stat.color} transition-transform group-hover:scale-110 duration-300`}>
                <stat.icon size={24} />
              </div>
            </div>
            <h3 className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{stat.label}</h3>
            <p className="text-xl font-black text-slate-900 mt-1 tracking-tight">{stat.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Gráfico de Fluxo */}
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h3 className="font-black text-slate-800 text-sm uppercase tracking-widest flex items-center">
                <TrendingUp size={16} className="mr-2 text-blue-600" /> Fluxo de Caixa (6 Meses)
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Comparativo de Entradas e Saídas</p>
            </div>
          </div>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#2563eb" stopOpacity={0.15}/>
                    <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} 
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}}
                  tickFormatter={(value) => `R$ ${value / 1000}k`}
                />
                <Tooltip 
                  contentStyle={{ 
                    borderRadius: '20px', 
                    border: 'none', 
                    boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1)',
                    fontSize: '12px',
                    fontWeight: '900'
                  }}
                  formatter={(value: any) => [`R$ ${value.toLocaleString('pt-BR')}`, '']}
                />
                <Area 
                  type="monotone" 
                  dataKey="revenue" 
                  name="Entradas"
                  stroke="#2563eb" 
                  strokeWidth={4} 
                  fillOpacity={1} 
                  fill="url(#colorRev)" 
                />
                <Area 
                  type="monotone" 
                  dataKey="costs" 
                  name="Saídas"
                  stroke="#cbd5e1" 
                  strokeWidth={2} 
                  strokeDasharray="5 5"
                  fill="transparent" 
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Próximas Movimentações */}
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm flex flex-col">
          <div className="mb-8">
            <h3 className="font-black text-slate-800 text-sm uppercase tracking-widest flex items-center">
              <Clock size={16} className="mr-2 text-blue-600" /> Próximas Movimentações
            </h3>
            <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Agenda de faturas a vencer</p>
          </div>

          <div className="flex-1 space-y-4">
            {upcomingMovements.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-slate-300 py-10">
                <Calendar size={48} className="mb-4 opacity-10" />
                <p className="text-xs font-black uppercase tracking-widest">Sem previsões</p>
              </div>
            ) : (
              upcomingMovements.map((mov) => (
                <div key={mov.id} className="flex items-center justify-between p-4 bg-slate-50/50 hover:bg-slate-100 rounded-2xl transition-all group">
                  <div className="flex items-center space-x-4">
                    <div className={`p-2 rounded-xl ${mov.tipo === 'Entrada' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                      {mov.tipo === 'Entrada' ? <ArrowUpRight size={18} strokeWidth={3} /> : <ArrowDownRight size={18} strokeWidth={3} />}
                    </div>
                    <div>
                      <p className="text-xs font-black text-slate-800 line-clamp-1">{mov.descricao}</p>
                      <div className="flex items-center mt-0.5">
                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">
                          {new Date(mov.vencimento + 'T12:00:00').toLocaleDateString('pt-BR')}
                        </span>
                      </div>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`text-sm font-black ${mov.tipo === 'Entrada' ? 'text-green-600' : 'text-red-600'}`}>
                      R$ {mov.valor.toLocaleString('pt-BR')}
                    </p>
                  </div>
                </div>
              ))
            )}
          </div>

          <div className="mt-8 pt-6 border-t border-slate-50">
            <p className="text-[9px] text-center font-black text-slate-300 uppercase tracking-widest">
              Dados atualizados em tempo real
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Sparkles, Loader2, Send, BrainCircuit, X, TrendingUp, TrendingDown, Wallet, AlertCircle, Calendar, Wrench, Users } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { collection, query, where, getDocs, updateDoc, doc, addDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '../firebase';
import { Client, Movement, Service } from '../types';

interface AICommandCenterProps {
  clients: Client[];
  movements: Movement[];
  services: Service[];
}

export const AICommandCenter: React.FC<AICommandCenterProps> = ({ clients, movements, services }) => {
  const [input, setInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [responseContent, setResponseContent] = useState<{ title: string; text: string; type: 'info' | 'finance' | 'agenda' } | null>(null);

  const handleCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isProcessing) return;

    setIsProcessing(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Definição expandida de funções para a IA
    const tools = [{
      functionDeclarations: [
        {
          name: 'processPayment',
          description: 'Registra ou consolida um pagamento realizado.',
          parameters: {
            type: Type.OBJECT,
            properties: {
              clientName: { type: Type.STRING, description: 'Nome do cliente ou fornecedor.' },
              amount: { type: Type.NUMBER, description: 'Valor da transação.' }
            },
            required: ['clientName', 'amount']
          }
        },
        {
          name: 'getFinancialHealth',
          description: 'Analisa a saúde financeira, lucros e gastos do mês.'
        },
        {
          name: 'getAgenda',
          description: 'Consulta serviços agendados e compromissos financeiros para um período (hoje, semana, mês).',
          parameters: {
            type: Type.OBJECT,
            properties: {
              period: { type: Type.STRING, enum: ['hoje', 'semana', 'mes'], description: 'O período de tempo da consulta.' }
            },
            required: ['period']
          }
        },
        {
          name: 'searchClientInfo',
          description: 'Busca informações detalhadas sobre um cliente específico.',
          parameters: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING, description: 'Nome do cliente a buscar.' }
            },
            required: ['name']
          }
        }
      ]
    }];

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: input,
        config: { 
          tools,
          systemInstruction: `Você é o Assistente Executivo da JPS Steel - Montagens Industriais. 
          Sua missão é facilitar a gestão de Patricia e da equipe. 
          - Se o usuário perguntar sobre o futuro (agenda, o que tem pra hoje/semana), use getAgenda.
          - Se for sobre dinheiro, use getFinancialHealth ou processPayment.
          - Se for sobre um cliente específico, use searchClientInfo.
          - Se for uma pergunta geral sobre a empresa ou manutenção, responda amigavelmente sem ferramentas.
          Mantenha as respostas curtas, profissionais e úteis.`
        },
      });

      const call = response.functionCalls?.[0];

      if (!call) {
        // Resposta Conversacional Geral
        setResponseContent({
          title: "Assistente JPS",
          text: response.text || "Estou à disposição para ajudar com a gestão da JPS Steel.",
          type: 'info'
        });
        setShowResponseModal(true);
      } else {
        // Processamento de Function Calling
        switch (call.name) {
          case 'processPayment':
            const { clientName, amount } = call.args as any;
            await handlePaymentLogic(clientName, amount);
            alert(`Sucesso: Pagamento de R$ ${amount} para ${clientName} processado.`);
            break;

          case 'getFinancialHealth':
            await handleFinancialSummary();
            break;

          case 'getAgenda':
            await handleAgendaLogic((call.args as any).period);
            break;

          case 'searchClientInfo':
            await handleClientInfoLogic((call.args as any).name);
            break;
        }
      }
      setInput('');
    } catch (error) {
      console.error("Erro na IA:", error);
      alert("Erro ao processar comando IA.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleAgendaLogic = async (period: string) => {
    const today = new Date();
    const end = new Date();
    if (period === 'semana') end.setDate(today.getDate() + 7);
    else if (period === 'mes') end.setMonth(today.getMonth() + 1);
    else end.setHours(23, 59, 59);

    const filteredServices = services.filter(s => {
      const d = new Date(s.dataServico + 'T12:00:00');
      return d >= today && d <= end;
    });

    const filteredMovements = movements.filter(m => {
      const d = new Date(m.vencimento + 'T12:00:00');
      return d >= today && d <= end && m.status === 'Pendente';
    });

    const summary = `Agenda para ${period}:
    - Serviços: ${filteredServices.length > 0 ? filteredServices.map(s => `${s.nomeCliente} (${s.dataServico})`).join(', ') : 'Nenhum serviço agendado.'}
    - Financeiro Pendente: ${filteredMovements.length > 0 ? filteredMovements.map(m => `${m.descricao} (R$ ${m.valor})`).join(', ') : 'Nenhum vencimento.'}`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const finalResp = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Com base nestes dados: ${summary}, responda à pergunta do usuário: "${input}" de forma organizada.`
    });

    setResponseContent({
      title: `Agenda: ${period.toUpperCase()}`,
      text: finalResp.text || '',
      type: 'agenda'
    });
    setShowResponseModal(true);
  };

  const handleClientInfoLogic = async (name: string) => {
    const client = clients.find(c => c.displayName.toLowerCase().includes(name.toLowerCase()));
    if (!client) {
      setResponseContent({ title: "Busca de Cliente", text: `Não encontrei nenhum cliente com o nome "${name}" em nossa base.`, type: 'info' });
    } else {
      const clientServices = services.filter(s => s.clienteRelacionado === client.id);
      const text = `Cliente: ${client.displayName}\nCNPJ: ${client.cnpj}\nEndereço: ${client.endereco}\nServiços realizados: ${clientServices.length}\nStatus: Ativo no sistema JPS.`;
      setResponseContent({ title: "Ficha do Cliente", text, type: 'info' });
    }
    setShowResponseModal(true);
  };

  const handleFinancialSummary = async () => {
    const totalIn = movements.filter(m => m.tipo === 'Entrada' && m.status !== 'Cancelado').reduce((acc, curr) => acc + curr.valor, 0);
    const totalOut = movements.filter(m => m.tipo === 'Saída' && m.status !== 'Cancelado').reduce((acc, curr) => acc + curr.valor, 0);

    const prompt = `Dados Financeiros JPS Steel:
    Entradas: R$ ${totalIn}
    Saídas: R$ ${totalOut}
    Saldo: R$ ${totalIn - totalOut}

    Analise o mês e dê um conselho estratégico rápido.`;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });

    setResponseContent({
      title: "Análise Financeira",
      text: response.text || '',
      type: 'finance'
    });
    setShowResponseModal(true);
  };

  const handlePaymentLogic = async (clientName: string, amount: number) => {
    const client = clients.find(c => c.displayName.toLowerCase().includes(clientName.toLowerCase()));
    const q = query(collection(db, 'financeiro'), where('valor', '==', amount), where('status', '==', 'Pendente'));
    const snap = await getDocs(q);

    if (!snap.empty) {
      await updateDoc(doc(db, 'financeiro', snap.docs[0].id), { status: 'Consolidado', updatedAt: serverTimestamp() });
    } else {
      await addDoc(collection(db, 'financeiro'), {
        tipo: 'Saída', categoria: 'Geral', descricao: `Pagamento: ${clientName}`, valor: amount,
        status: 'Consolidado', vencimento: new Date().toISOString().split('T')[0],
        idRelacionado: client?.id || '', createdAt: serverTimestamp()
      });
    }
  };

  return (
    <div className="relative z-50 mb-8">
      <form onSubmit={handleCommand} className="group relative">
        <div className="absolute inset-0 bg-gradient-to-r from-blue-600/20 to-purple-600/20 rounded-3xl blur-xl opacity-0 group-hover:opacity-100 transition-opacity"></div>
        <div className="relative flex items-center bg-white border-2 border-slate-100 p-2 rounded-3xl shadow-xl focus-within:border-blue-500 transition-all ring-4 ring-slate-100/50">
          <div className={`p-3 rounded-2xl ${isProcessing ? 'bg-blue-600 text-white animate-pulse' : 'bg-slate-900 text-white'}`}>
            {isProcessing ? <BrainCircuit size={22} className="animate-spin" /> : <Sparkles size={22} />}
          </div>
          <input 
            type="text" 
            placeholder="Ex: 'O que temos pra essa semana?' ou 'Paguei 500 para Givaudan'"
            className="flex-1 px-4 py-2 bg-transparent outline-none font-bold text-black placeholder:text-slate-400 text-sm"
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button 
            type="submit"
            disabled={isProcessing || !input.trim()}
            className="p-3 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 disabled:opacity-30 transition-all shadow-lg shadow-blue-600/20"
          >
            {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
          </button>
        </div>
      </form>

      {/* Modal de Resposta da IA */}
      {showResponseModal && responseContent && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-xl z-[200] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300 border border-white/20">
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
               <div className="flex items-center space-x-3">
                  <div className={`p-3 rounded-2xl ${
                    responseContent.type === 'finance' ? 'bg-green-600' : 
                    responseContent.type === 'agenda' ? 'bg-blue-600' : 'bg-slate-700'
                  }`}>
                    {responseContent.type === 'finance' ? <TrendingUp size={24} /> : 
                     responseContent.type === 'agenda' ? <Calendar size={24} /> : <BrainCircuit size={24} />}
                  </div>
                  <div>
                    <h3 className="font-black text-lg uppercase tracking-tight">{responseContent.title}</h3>
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Resposta da Inteligência Artificial</p>
                  </div>
               </div>
               <button onClick={() => setShowResponseModal(false)} className="p-2 bg-white/10 hover:bg-white/20 rounded-xl transition-colors">
                 <X size={20} />
               </button>
            </div>

            <div className="p-8 space-y-6">
               <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 min-h-[120px]">
                  <p className="text-sm text-slate-800 leading-relaxed font-medium whitespace-pre-wrap">
                    {responseContent.text}
                  </p>
               </div>

               <button 
                onClick={() => setShowResponseModal(false)}
                className="w-full py-4 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:bg-slate-800 transition-all uppercase tracking-widest text-xs"
               >
                 Fechar Assistente
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area 
} from 'recharts';
import { 
  Users, 
  Briefcase, 
  TrendingUp, 
  AlertCircle,
  ArrowUpRight,
  ArrowDownRight,
  Clock,
  Calendar
} from 'lucide-react';
import { collection, onSnapshot, query, orderBy, limit } from 'firebase/firestore';
import { db } from '../firebase';
import { Client, Service, Movement } from '../types';
import { AICommandCenter } from './AICommandCenter';

export const Dashboard: React.FC = () => {
  const [clients, setClients] = useState<Client[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [movements, setMovements] = useState<Movement[]>([]);

  useEffect(() => {
    const unsubClients = onSnapshot(collection(db, 'cliente'), (snap) => {
      setClients(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Client)));
    });

    const unsubServices = onSnapshot(collection(db, 'servico'), (snap) => {
      setServices(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Service)));
    });

    const unsubMovements = onSnapshot(collection(db, 'financeiro'), (snap) => {
      setMovements(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Movement)));
    });

    return () => {
      unsubClients();
      unsubServices();
      unsubMovements();
    };
  }, []);

  // 1. Estatísticas Calculadas
  const stats = useMemo(() => {
    const today = new Date();
    const currentMonth = today.getMonth();
    const currentYear = today.getFullYear();

    // Total Clientes
    const totalClients = clients.length;

    // Serviços Ativos
    const activeServices = services.filter(s => s.statusServico === 'Em execução' || s.statusServico === 'Aguardando início').length;

    // Faturamento Mês
    const monthlyRevenue = movements
      .filter(m => {
        if (m.tipo !== 'Entrada' || m.status === 'Cancelado' || m.status === 'Arquivado') return false;
        const vDate = new Date(m.vencimento + 'T12:00:00');
        return vDate.getMonth() === currentMonth && vDate.getFullYear() === currentYear;
      })
      .reduce((acc, curr) => acc + curr.valor, 0);

    // Valor Total das Movimentações Pendentes
    const pendingTotal = movements
      .filter(m => m.status === 'Pendente')
      .reduce((acc, curr) => acc + curr.valor, 0);

    return [
      { label: 'Total Clientes', value: totalClients, icon: Users, color: 'text-blue-600', bg: 'bg-blue-50' },
      { label: 'Serviços Ativos', value: activeServices, icon: Briefcase, color: 'text-orange-600', bg: 'bg-orange-50' },
      { label: 'Faturamento Mês', value: `R$ ${monthlyRevenue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`, icon: TrendingUp, color: 'text-green-600', bg: 'bg-green-50' },
      { label: 'Total Pendente', value: `R$ ${pendingTotal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`, icon: AlertCircle, color: 'text-red-600', bg: 'bg-red-50' },
    ];
  }, [clients, services, movements]);

  // 2. Dados do Gráfico (Últimos 6 meses)
  const chartData = useMemo(() => {
    const monthNames = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const last6Months = [];

    for (let i = 5; i >= 0; i--) {
      const d = new Date();
      d.setMonth(d.getMonth() - i);
      const m = d.getMonth();
      const y = d.getFullYear();

      const revenue = movements
        .filter(mov => {
          if (mov.tipo !== 'Entrada' || mov.status === 'Cancelado' || mov.status === 'Arquivado') return false;
          const vDate = new Date(mov.vencimento + 'T12:00:00');
          return vDate.getMonth() === m && vDate.getFullYear() === y;
        })
        .reduce((acc, curr) => acc + curr.valor, 0);

      const costs = movements
        .filter(mov => {
          if (mov.tipo !== 'Saída' || mov.status === 'Cancelado' || mov.status === 'Arquivado') return false;
          const vDate = new Date(mov.vencimento + 'T12:00:00');
          return vDate.getMonth() === m && vDate.getFullYear() === y;
        })
        .reduce((acc, curr) => acc + curr.valor, 0);

      last6Months.push({
        name: monthNames[m],
        revenue,
        costs
      });
    }
    return last6Months;
  }, [movements]);

  // 3. Próximas Movimentações
  const upcomingMovements = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    return movements
      .filter(m => m.vencimento >= todayStr && m.status !== 'Arquivado' && m.status !== 'Cancelado')
      .sort((a, b) => a.vencimento.localeCompare(b.vencimento))
      .slice(0, 5);
  }, [movements]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">Painel Analítico</h1>
          <p className="text-slate-500 text-sm font-medium">Acompanhamento consolidado da JPS Steel.</p>
        </div>
      </div>

      {/* AI CommandCenter INTEGRATION WITH FULL CONTEXT */}
      <AICommandCenter clients={clients} movements={movements} services={services} />

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm hover:shadow-md transition-all group">
            <div className="flex items-center justify-between mb-4">
              <div className={`p-3 rounded-2xl ${stat.bg} ${stat.color} transition-transform group-hover:scale-110 duration-300`}>
                <stat.icon size={24} />
              </div>
            </div>
            <h3 className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{stat.label}</h3>
            <p className="text-xl font-black text-slate-900 mt-1 tracking-tight">{stat.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Gráfico de Fluxo */}
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h3 className="font-black text-slate-800 text-sm uppercase tracking-widest flex items-center">
                <TrendingUp size={16} className="mr-2 text-blue-600" /> Fluxo de Caixa (6 Meses)
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Comparativo de Entradas e Saídas</p>
            </div>
          </div>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#2563eb" stopOpacity={0.15}/>
                    <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} 
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}}
                  tickFormatter={(value) => `R$ ${value / 1000}k`}
                />
                <Tooltip 
                  contentStyle={{ 
                    borderRadius: '20px', 
                    border: 'none', 
                    boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1)',
                    fontSize: '12px',
                    fontWeight: '900'
                  }}
                  formatter={(value: any) => [`R$ ${value.toLocaleString('pt-BR')}`, '']}
                />
                <Area 
                  type="monotone" 
                  dataKey="revenue" 
                  name="Entradas"
                  stroke="#2563eb" 
                  strokeWidth={4} 
                  fillOpacity={1} 
                  fill="url(#colorRev)" 
                />
                <Area 
                  type="monotone" 
                  dataKey="costs" 
                  name="Saídas"
                  stroke="#cbd5e1" 
                  strokeWidth={2} 
                  strokeDasharray="5 5"
                  fill="transparent" 
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Próximas Movimentações */}
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm flex flex-col">
          <div className="mb-8">
            <h3 className="font-black text-slate-800 text-sm uppercase tracking-widest flex items-center">
              <Clock size={16} className="mr-2 text-blue-600" /> Próximas Movimentações
            </h3>
            <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">Agenda de faturas a vencer</p>
          </div>

          <div className="flex-1 space-y-4">
            {upcomingMovements.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-slate-300 py-10">
                <Calendar size={48} className="mb-4 opacity-10" />
                <p className="text-xs font-black uppercase tracking-widest">Sem previsões</p>
              </div>
            ) : (
              upcomingMovements.map((mov) => (
                <div key={mov.id} className="flex items-center justify-between p-4 bg-slate-50/50 hover:bg-slate-100 rounded-2xl transition-all group">
                  <div className="flex items-center space-x-4">
                    <div className={`p-2 rounded-xl ${mov.tipo === 'Entrada' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                      {mov.tipo === 'Entrada' ? <ArrowUpRight size={18} strokeWidth={3} /> : <ArrowDownRight size={18} strokeWidth={3} />}
                    </div>
                    <div>
                      <p className="text-xs font-black text-slate-800 line-clamp-1">{mov.descricao}</p>
                      <div className="flex items-center mt-0.5">
                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">
                          {new Date(mov.vencimento + 'T12:00:00').toLocaleDateString('pt-BR')}
                        </span>
                      </div>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className={`text-sm font-black ${mov.tipo === 'Entrada' ? 'text-green-600' : 'text-red-600'}`}>
                      R$ {mov.valor.toLocaleString('pt-BR')}
                    </p>
                  </div>
                </div>
              ))
            )}
          </div>

          <div className="mt-8 pt-6 border-t border-slate-50">
            <p className="text-[9px] text-center font-black text-slate-300 uppercase tracking-widest">
              Dados atualizados em tempo real
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

