import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { Clients } from './components/Clients';
import { Services } from './components/Services';
import { BudgetCalculator } from './components/BudgetCalculator';
import { InventoryMovements } from './components/InventoryMovements';
import { AllMovementsList } from './components/AllMovementsList';
import { Passwords } from './components/Passwords';
import { Settings } from './components/Settings';
import { Page } from './types';
import { Lock, ShieldAlert, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.Dashboard);
  const [redirectClientId, setRedirectClientId] = useState<string | null>(null);
  const [budgetToClone, setBudgetToClone] = useState<any>(null);

  // PIN Protection State
  const [isPinModalOpen, setIsPinModalOpen] = useState(false);
  const [pinInput, setPinInput] = useState('');
  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const REQUIRED_PIN = "101222";

  const handleBudgetFinish = (clientId: string) => {
    setBudgetToClone(null);
    setRedirectClientId(clientId);
    setCurrentPage(Page.Clients);
  };

  const navigateTo = (page: Page) => {
    if (page === Page.Passwords) {
      setIsPinModalOpen(true);
      setPinInput('');
    } else {
      if (page !== Page.Budget) setBudgetToClone(null);
      setCurrentPage(page);
    }
  };

  const handlePinSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsAuthenticating(true);

    // Pequeno delay para UX
    setTimeout(() => {
      if (pinInput === REQUIRED_PIN) {
        setCurrentPage(Page.Passwords);
        setIsPinModalOpen(false);
      } else {
        alert("Falta de autorização! PIN incorreto.");
        setIsPinModalOpen(false);
        setCurrentPage(Page.Dashboard);
      }
      setIsAuthenticating(false);
    }, 600);
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.Dashboard:
        return <Dashboard />;
      case Page.Clients:
        return (
          <Clients 
            initialClientId={redirectClientId} 
            onClearRedirect={() => setRedirectClientId(null)} 
            onCloneBudget={(data) => {
              setBudgetToClone(data);
              setCurrentPage(Page.Budget);
            }}
          />
        );
      case Page.Services:
        return <Services />;
      case Page.Budget:
        return <BudgetCalculator initialData={budgetToClone} onFinish={handleBudgetFinish} />;
      case Page.Movements:
        return <InventoryMovements onNavigateToAll={() => setCurrentPage(Page.AllMovements)} />;
      case Page.AllMovements:
        return <AllMovementsList onBack={() => setCurrentPage(Page.Movements)} />;
      case Page.Passwords:
        return <Passwords />;
      case Page.Settings:
        return <Settings />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <>
      <Layout activePage={currentPage} onNavigate={navigateTo}>
        {renderPage()}
      </Layout>

      {/* PIN Access Modal */}
      {isPinModalOpen && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[150] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
            <div className="p-8 flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center text-white mb-6 shadow-xl shadow-blue-500/20">
                <Lock size={32} />
              </div>
              <h3 className="text-xl font-black text-slate-900 mb-2 uppercase tracking-tighter">Área Restrita</h3>
              <p className="text-slate-800 text-xs font-bold mb-8">Digite o PIN de acesso para visualizar as credenciais confidenciais.</p>

              <form onSubmit={handlePinSubmit} className="w-full space-y-4">
                <input 
                  type="password"
                  autoFocus
                  maxLength={6}
                  placeholder="••••••"
                  className="w-full py-4 bg-slate-100 border-2 border-slate-100 focus:border-blue-600 focus:bg-white rounded-2xl text-center text-2xl font-black tracking-[0.5em] transition-all outline-none text-black"
                  value={pinInput}
                  onChange={e => setPinInput(e.target.value)}
                />

                <button 
                  type="submit"
                  disabled={isAuthenticating || pinInput.length < 4}
                  className="w-full py-4 bg-slate-900 hover:bg-slate-800 text-white font-black rounded-2xl shadow-xl active:scale-[0.98] transition-all disabled:opacity-50 flex items-center justify-center space-x-2"
                >
                  {isAuthenticating ? <Loader2 className="animate-spin" size={20} /> : <span>VALIDAR ACESSO</span>}
                </button>

                <button 
                  type="button"
                  onClick={() => setIsPinModalOpen(false)}
                  className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-red-500 transition-colors"
                >
                  Cancelar Navegação
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Search, Edit2, Trash2, MapPin, Building2, ChevronRight
} from 'lucide-react';
import { collection, addDoc, onSnapshot, deleteDoc, doc, updateDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '../firebase';
import { Client } from '../types';
import { ClientForm } from './ClientForm';
import { ClientDetails } from './ClientDetails';
import { ConfirmationDialog } from './ConfirmationDialog';

interface ClientsProps {
  initialClientId?: string | null;
  onClearRedirect?: () => void;
  onCloneBudget?: (budget: any) => void;
}

export const Clients: React.FC<ClientsProps> = ({ initialClientId, onClearRedirect, onCloneBudget }) => {
  const [clients, setClients] = useState<Client[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);

  const [isConfirmOpen, setIsConfirmOpen] = useState(false);
  const [clientToDelete, setClientToDelete] = useState<string | null>(null);

  useEffect(() => {
    const unsub = onSnapshot(collection(db, 'cliente'), (snap) => {
      const clientList = snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Client));
      setClients(clientList);

      // Auto-seleção se houver um redirecionamento pendente
      if (initialClientId) {
        const found = clientList.find(c => c.id === initialClientId);
        if (found) {
          setSelectedClient(found);
          if (onClearRedirect) onClearRedirect();
        }
      }
    });
    return () => unsub();
  }, [initialClientId]);

  const handleFormSubmit = async (formData: any) => {
    try {
      if (editingClient) {
        await updateDoc(doc(db, 'cliente', editingClient.id), formData);
      } else {
        await addDoc(collection(db, 'cliente'), {
          ...formData,
          createdAt: serverTimestamp()
        });
      }
    } catch (err) {
      console.error("Erro ao salvar no Firestore:", err);
      throw err;
    }
  };

  const openDeleteConfirm = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setClientToDelete(id);
    setIsConfirmOpen(true);
  };

  const handleConfirmDelete = async () => {
    if (!clientToDelete) return;
    try {
      await deleteDoc(doc(db, 'cliente', clientToDelete));
      if (selectedClient?.id === clientToDelete) setSelectedClient(null);
    } catch (err) {
      console.error("Erro ao excluir cliente:", err);
    } finally {
      setIsConfirmOpen(false);
      setClientToDelete(null);
    }
  };

  const handleEdit = (e: React.MouseEvent, client: Client) => {
    e.stopPropagation();
    setEditingClient(client);
    setIsModalOpen(true);
  };

  const filteredClients = clients.filter(c => 
    (c.displayName?.toLowerCase().includes(searchTerm.toLowerCase())) || 
    (c.cnpj?.includes(searchTerm))
  );

  if (selectedClient) {
    return (
      <ClientDetails 
        client={selectedClient} 
        onBack={() => setSelectedClient(null)} 
        onCloneBudget={onCloneBudget}
      />
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Clientes</h1>
          <p className="text-slate-500">Gerencie a base de clientes e seus representantes.</p>
        </div>
        <button 
          onClick={() => { setEditingClient(null); setIsModalOpen(true); }}
          className="flex items-center justify-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl font-semibold transition-all shadow-lg shadow-blue-900/20"
        >
          <Plus size={20} />
          <span>Novo Cliente</span>
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50/50">
          <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar por nome ou CNPJ..." 
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all text-slate-900 font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider font-bold">
              <tr>
                <th className="px-6 py-4">Empresa / CNPJ</th>
                <th className="px-6 py-4">Localização</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredClients.map((client) => (
                <tr 
                  key={client.id} 
                  onClick={() => setSelectedClient(client)}
                  className="hover:bg-blue-50/30 transition-colors group cursor-pointer"
                >
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <div className="w-10 h-10 rounded-lg overflow-hidden border border-slate-200 bg-slate-100 flex-shrink-0 shadow-sm">
                        <img src={client.fotoUrl || "https://i.ibb.co/LdxXv1CF/empresa-Oliginal.png"} alt={client.displayName} className="w-full h-full object-cover" />
                      </div>
                      <div>
                        <p className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors">{client.displayName}</p>
                        <p className="text-xs text-slate-400 font-mono mt-0.5">{client.cnpj}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center text-xs text-slate-600 max-w-xs truncate">
                      <MapPin size={12} className="mr-2 text-slate-400 flex-shrink-0" />
                      {client.endereco || 'Endereço não informado'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end items-center space-x-2">
                      <button 
                        onClick={(e) => handleEdit(e, client)}
                        className="p-2.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                        title="Editar"
                      >
                        <Edit2 size={16} />
                      </button>
                      <button 
                        onClick={(e) => openDeleteConfirm(e, client.id)}
                        className="p-2.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                        title="Excluir"
                      >
                        <Trash2 size={16} />
                      </button>
                      <div className="pl-2 border-l border-slate-100 ml-2">
                        <ChevronRight size={18} className="text-slate-300 group-hover:text-blue-400 transition-colors" />
                      </div>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredClients.length === 0 && (
                <tr>
                  <td colSpan={3} className="px-6 py-12 text-center text-slate-400">
                    <div className="flex flex-col items-center">
                      <Building2 size={40} className="mb-2 opacity-20" />
                      <p>Nenhum cliente encontrado.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <ClientForm 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSubmit={handleFormSubmit}
        initialData={editingClient}
      />

      <ConfirmationDialog 
        isOpen={isConfirmOpen}
        title="Excluir Cliente"
        message="Deseja realmente excluir este cliente? Todos os dados vinculados serão perdidos permanentemente."
        confirmLabel="Excluir"
        onConfirm={handleConfirmDelete}
        onCancel={() => setIsConfirmOpen(false)}
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  ArrowLeft, Building2, MapPin, FileText, Briefcase, 
  UserPlus, Phone, Mail, Users, Trash2, Calendar, Eye, X, 
  MapPin as MapPinIcon, Phone as PhoneIcon, Globe as GlobeIcon, FileDown,
  Edit2, Copy
} from 'lucide-react';
import { 
  collection, addDoc, onSnapshot, query, orderBy, 
  serverTimestamp, deleteDoc, doc, where, updateDoc 
} from 'firebase/firestore';
import { db } from '../firebase';
import { Client, Representative } from '../types';
import { RepresentativeForm } from './RepresentativeForm';
import { ConfirmationDialog } from './ConfirmationDialog';

interface ClientDetailsProps {
  client: Client;
  onBack: () => void;
  onCloneBudget?: (budget: any) => void;
}

export const ClientDetails: React.FC<ClientDetailsProps> = ({ client, onBack, onCloneBudget }) => {
  const [representatives, setRepresentatives] = useState<Representative[]>([]);
  const [budgets, setBudgets] = useState<any[]>([]);
  const [isRepFormOpen, setIsRepFormOpen] = useState(false);
  const [editingRepresentative, setEditingRepresentative] = useState<Representative | null>(null);
  const [selectedBudget, setSelectedBudget] = useState<any | null>(null);

  const [isConfirmOpen, setIsConfirmOpen] = useState(false);
  const [repToDelete, setRepToDelete] = useState<string | null>(null);
  const [isConfirmBudgetDeleteOpen, setIsConfirmBudgetDeleteOpen] = useState(false);
  const [budgetIdToDelete, setBudgetIdToDelete] = useState<string | null>(null);

  const APP_LOGO = "https://res.cloudinary.com/dcp9d15n4/image/upload/v1768585071/logo_f7a8go.png";

  useEffect(() => {
    const qReps = query(
      collection(db, 'cliente', client.id, 'representantes'),
      orderBy('createdAt', 'desc')
    );
    const unsubReps = onSnapshot(qReps, (snap) => {
      setRepresentatives(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Representative)));
    });

    const qBudgets = query(
      collection(db, 'orcamento'),
      where('idContratante', '==', client.id)
    );

    const unsubBudgets = onSnapshot(qBudgets, (snap) => {
      const budgetData = snap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      budgetData.sort((a, b) => {
        const dateA = a.createdAt?.seconds || 0;
        const dateB = b.createdAt?.seconds || 0;
        return dateB - dateA;
      });
      setBudgets(budgetData);
    });

    return () => {
      unsubReps();
      unsubBudgets();
    };
  }, [client.id]);

  const handleOpenNewRep = () => {
    setEditingRepresentative(null);
    setIsRepFormOpen(true);
  };

  const handleEditRep = (rep: Representative) => {
    setEditingRepresentative(rep);
    setIsRepFormOpen(true);
  };

  const handleRepresentativeSubmit = async (data: Omit<Representative, 'id'>) => {
    try {
      if (editingRepresentative) {
        await updateDoc(doc(db, 'cliente', client.id, 'representantes', editingRepresentative.id), {
          ...data,
          updatedAt: serverTimestamp()
        });
      } else {
        await addDoc(collection(db, 'cliente', client.id, 'representantes'), {
          ...data,
          createdAt: serverTimestamp()
        });
      }
    } catch (err) {
      console.error("Erro ao salvar representante:", err);
